import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './components/Login';
import { authService } from './services/api';

const ProtectedRoute = ({ children }) => {
  if (!authService.isAuthenticated()) {
    return <Navigate to="/login" />;
  }
  return children;
};

const Dashboard = () => {
  const user = authService.getCurrentUser();
  
  const handleLogout = () => {
    authService.logout();
    window.location.href = '/login';
  };

  return (
    <div style={styles.dashboard}>
      <div style={styles.header}>
        <h1>Gestionytics - Dashboard</h1>
        <button onClick={handleLogout} style={styles.logoutButton}>
          Cerrar Sesión
        </button>
      </div>
      
      <div style={styles.userInfo}>
        <h2>Bienvenido, {user?.nombreUsuario}!</h2>
        <p><strong>Nombre completo:</strong> {user?.nombre} {user?.apellido}</p>
        <p><strong>Correo:</strong> {user?.correoElectronico}</p>
        <p><strong>Coordinador asignado:</strong> {user?.coordinadorAsignado?.nombre}</p>
      </div>

      <div style={styles.card}>
        <h3>Resumen de Ofertas</h3>
        <p>Aquí irán las ofertas del usuario...</p>
      </div>
    </div>
  );
};

const styles = {
  dashboard: {
    padding: '20px',
    fontFamily: 'Arial, sans-serif'
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    backgroundColor: '#2c3e50',
    color: 'white',
    padding: '15px 30px',
    borderRadius: '8px',
    marginBottom: '30px'
  },
  logoutButton: {
    backgroundColor: '#e74c3c',
    color: 'white',
    border: 'none',
    padding: '10px 20px',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px',
    fontWeight: 'bold'
  },
  userInfo: {
    backgroundColor: '#ecf0f1',
    padding: '20px',
    borderRadius: '8px',
    marginBottom: '20px'
  },
  card: {
    backgroundColor: 'white',
    padding: '20px',
    borderRadius: '8px',
    boxShadow: '0 2px 5px rgba(0,0,0,0.1)'
  }
};

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route 
          path="/dashboard" 
          element={
            <ProtectedRoute>
              <Dashboard />
            </ProtectedRoute>
          } 
        />
        <Route path="/" element={<Navigate to="/login" />} />
      </Routes>
    </Router>
  );
}

export default App;
